import { ACTIVITY_TYPES } from '@motivation/shared';
import { navigate } from '../../router.js';
import { createActivityAndOpenHub } from './activity-create.js';
import { appTodayString } from '../../services/app-timezone.service.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import { HEALTH_EVENTS } from './health-events.js';
import './week-widget/week-widget.component.js';
import './health-timeline/health-timeline.component.js';
import './quick-log-bar/quick-log-bar.component.js';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createComponentLogger } from '../../utils/component-logger.js';
import { safeExec } from '../../utils/safe-exec.js';
import { documentStyleSheet } from '../../utils/css.js';
import themeStyles from './health-theme.css?inline';
import dashboardStyles from './health-dashboard-screen.css?inline';

documentStyleSheet(themeStyles);
documentStyleSheet(dashboardStyles);

const template = document.createElement('template');
template.innerHTML = `
    <pre class="screen-error health-screen-error" hidden></pre>

    <div class="health-screen-body">
        <week-widget></week-widget>
        <health-timeline></health-timeline>
    </div>

    <quick-log-bar class="health-quick-log"></quick-log-bar>

    <div class="more-menu" id="more-menu" hidden>
        <button class="more-option" id="more-food" type="button">🍽 Add Food</button>
        <button class="more-option" id="more-activity" type="button">🏃 Log Activity</button>
        <button class="more-option" id="more-template" type="button">📋 Start from Template</button>
        <button class="more-option" id="more-weight" type="button">⚖️ Log Weight</button>
        <button class="more-option" id="more-meals" type="button">📒 Manage Meals</button>
    </div>

    <dialog class="activity-dialog" id="activity-dialog">
        <form method="dialog" id="activity-form">
            <h2>Log Activity</h2>
            <div class="form-group">
                <label for="act-title">Title</label>
                <input type="text" id="act-title" name="title" required placeholder="e.g. Morning run">
            </div>
            <div class="form-group">
                <label for="act-type">Type</label>
                <select id="act-type" name="type">
                    ${ACTIVITY_TYPES.map(t => `<option value="${t}">${t.charAt(0).toUpperCase() + t.slice(1).replace(/_/g, ' ')}</option>`).join('\n                    ')}
                </select>
            </div>
            <div class="form-group">
                <label for="act-date">Date</label>
                <input type="date" id="act-date" name="date" required>
            </div>
            <div class="form-group">
                <label for="act-duration">Duration (minutes)</label>
                <input type="number" id="act-duration" name="duration" min="1" placeholder="60">
            </div>
            <div class="dialog-actions">
                <button value="cancel" formnovalidate>Cancel</button>
                <button value="save" class="btn-primary">Save</button>
            </div>
        </form>
    </dialog>
`;

export class HealthDashboardScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private readonly log = createComponentLogger('health-dashboard-screen');
    private moreMenuOpen = false;
    private contentRoot: HTMLElement | null = null;
    private errorEl: HTMLPreElement | null = null;

    setLoading(): void {
        // Per-component loading; screen-level setLoading is intentionally a no-op.
    }

    setError(err: unknown): void {
        if (!this.errorEl) return;
        this.errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        this.errorEl.hidden = false;
    }

    clearStatus(): void {
        if (this.errorEl) this.errorEl.hidden = true;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health', 'health', '/health');
        page.content.appendChild(template.content.cloneNode(true));
        this.contentRoot = page.content;
        this.errorEl = page.content.querySelector<HTMLPreElement>('.health-screen-error');

        this.wireMoreMenu();
        this.wireActivityDialog();
    }

    private wireMoreMenu(): void {
        const root = this.contentRoot!;
        // The quick-log bar's `›` (story 258) — the bar handles the meal
        // slots itself; everything else lives in this menu.
        root.addEventListener(HEALTH_EVENTS.QUICK_LOG_MORE, () => this.toggleMoreMenu());

        root.querySelector<HTMLButtonElement>('#more-food')!.addEventListener('click', () => {
            this.closeMoreMenu();
            // The generic add flow (no slot preset) — barcode + AI estimate
            // entry point; the bar's slot buttons cover the slotted case.
            navigate('/health/food-entry');
        });
        root.querySelector<HTMLButtonElement>('#more-activity')!.addEventListener('click', () => {
            this.closeMoreMenu();
            this.openManualAddDialog(appTodayString());
        });
        root.querySelector<HTMLButtonElement>('#more-template')!.addEventListener('click', () => {
            this.closeMoreMenu();
            navigate('/health/workout-templates');
        });
        root.querySelector<HTMLButtonElement>('#more-weight')!.addEventListener('click', () => {
            this.closeMoreMenu();
            navigate('/health/weight');
        });
        root.querySelector<HTMLButtonElement>('#more-meals')!.addEventListener('click', () => {
            this.closeMoreMenu();
            navigate('/health/meals');
        });
    }

    private wireActivityDialog(): void {
        const root = this.contentRoot!;
        const form = root.querySelector<HTMLFormElement>('#activity-form')!;
        const dialog = root.querySelector<HTMLDialogElement>('#activity-dialog')!;

        dialog.addEventListener('close', async () => {
            try {
                if (dialog.returnValue !== 'save') return;

                const data = Object.fromEntries(new FormData(form)) as Record<string, string>;
                if (!data.title || !data.date) return;

                await safeExec(this, this.log, async () => {
                    // Every new activity lands on the hub, where cardio/workout
                    // components are attached (story 181) — no more type branch.
                    await createActivityAndOpenHub({
                        title: data.title,
                        type: data.type,
                        date: data.date,
                        duration_minutes: data.duration ? parseInt(data.duration, 10) : undefined,
                    });
                }, { errorMessage: 'Failed to save activity' });
            } finally {
                form.reset();
            }
        });
    }

    private openManualAddDialog(dateStr: string): void {
        const root = this.contentRoot!;
        const dialog = root.querySelector<HTMLDialogElement>('#activity-dialog')!;
        const dateInput = root.querySelector<HTMLInputElement>('#act-date')!;
        dateInput.value = dateStr;
        dialog.showModal();
    }

    private toggleMoreMenu(): void {
        this.moreMenuOpen = !this.moreMenuOpen;
        this.contentRoot!.querySelector<HTMLElement>('#more-menu')!.hidden = !this.moreMenuOpen;
    }

    private closeMoreMenu(): void {
        this.moreMenuOpen = false;
        this.contentRoot!.querySelector<HTMLElement>('#more-menu')!.hidden = true;
    }
}

customElements.define('health-dashboard-screen', HealthDashboardScreen);
