import stylesText from './health-timeline.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { HealthService } from '../../../services/health.service.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { appTodayPlainDate } from '../../../services/app-timezone.service.js';
import { dayBurnKcal, weightKgOnDate } from '@motivation/shared';
import type { Activity } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);
import './timeline-day/timeline-day.component.js';
import type { TimelineDay } from './timeline-day/timeline-day.component.js';

const INITIAL_PAGE_SIZE = 14;
const APPEND_PAGE_SIZE = 14;
/** Weight lookback so MET burn estimates have a plausible body weight. */
const WEIGHT_LOOKBACK_DAYS = 90;

/**
 * Story 258 v3 — the spine timeline. Each page window is loaded with ranged
 * reads (summary, meaningful activities, weights, coaching dates) and sliced
 * into the day rows via their `data` property — rows do not fetch. Coaching
 * is server-only: its failure degrades the dots to hidden instead of failing
 * the window.
 */
const template = document.createElement('template');
template.innerHTML = `
    <div class="health-timeline-container">
        <div class="timeline-scroll-area">
            <div class="timeline-spine-layer"></div>
            <div id="timeline-list"></div>
            <pre class="screen-error" hidden></pre>
            <button class="screen-retry" type="button" hidden>Retry</button>
            <div id="timeline-sentinel" aria-hidden="true"></div>
        </div>
    </div>
`;

export class HealthTimeline extends HTMLElement {
    private readonly log = createComponentLogger('health-timeline');
    private observer: IntersectionObserver | null = null;
    private oldestRenderedDate: Temporal.PlainDate | null = null;
    /** Rows of the most recent window, kept for the retry path. */
    private lastWindow: { from: Temporal.PlainDate; to: Temporal.PlainDate; rows: TimelineDay[] } | null = null;
    /** Resolves when the most recent window load finishes. */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        shadow.querySelector<HTMLButtonElement>('.screen-retry')!.addEventListener('click', () => {
            if (this.lastWindow) {
                this.loadPromise = this.loadWindow(this.lastWindow.from, this.lastWindow.to, this.lastWindow.rows);
            }
        });
    }

    connectedCallback(): void {
        this.appendDays(INITIAL_PAGE_SIZE);

        const sentinel = this.shadowRoot!.getElementById('timeline-sentinel')!;
        this.observer = new IntersectionObserver((entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    this.appendDays(APPEND_PAGE_SIZE);
                    return;
                }
            }
        }, { rootMargin: '400px 0px' });
        this.observer.observe(sentinel);
    }

    disconnectedCallback(): void {
        this.observer?.disconnect();
        this.observer = null;
    }

    /**
     * Append N more day rows walking backwards from `oldestRenderedDate` (or
     * today on first call) and load their window. Public so tests can advance
     * the cursor deterministically without the IntersectionObserver.
     */
    appendDays(count: number): Promise<void> {
        const container = this.shadowRoot!.getElementById('timeline-list')!;
        let cursor = this.oldestRenderedDate
            ? this.oldestRenderedDate.subtract({ days: 1 })
            : appTodayPlainDate();
        const windowTo = cursor;

        const rows: TimelineDay[] = [];
        for (let i = 0; i < count; i++) {
            const day = document.createElement('timeline-day') as TimelineDay;
            day.setAttribute('date', cursor.toString());
            container.appendChild(day);
            rows.push(day);
            this.oldestRenderedDate = cursor;
            cursor = cursor.subtract({ days: 1 });
        }
        const windowFrom = this.oldestRenderedDate!;

        this.loadPromise = this.loadWindow(windowFrom, windowTo, rows);
        return this.loadPromise;
    }

    private async loadWindow(from: Temporal.PlainDate, to: Temporal.PlainDate, rows: TimelineDay[]): Promise<void> {
        this.lastWindow = { from, to, rows };
        const shadow = this.shadowRoot!;
        const errorEl = shadow.querySelector<HTMLElement>('.screen-error')!;
        const retryEl = shadow.querySelector<HTMLElement>('.screen-retry')!;
        try {
            const fromStr = from.toString();
            const toStr = to.toString();
            const weightFrom = from.subtract({ days: WEIGHT_LOOKBACK_DAYS }).toString();
            const [summaries, activities, weights, coachingDates] = await Promise.all([
                HealthService.fetchNutritionSummary(fromStr, toStr),
                HealthService.fetchMeaningfulActivitiesByDateRange(fromStr, toStr),
                HealthService.fetchWeightByDateRange(weightFrom, toStr),
                // Server-only — offline this degrades the dots, not the window.
                HealthService.fetchCoachingDates(fromStr, toStr).catch((err: unknown) => {
                    this.log.error('Coaching dates unavailable (hiding dots)', err);
                    return null;
                }),
            ]);

            const summaryByDate = new Map(summaries.map((s) => [s.date, s]));
            const activitiesByDate = new Map<string, Activity[]>();
            for (const activity of activities) {
                const list = activitiesByDate.get(activity.date) ?? [];
                list.push(activity);
                activitiesByDate.set(activity.date, list);
            }
            const coachingSet = coachingDates === null ? null : new Set(coachingDates);

            for (const row of rows) {
                const date = row.getAttribute('date')!;
                const dayActivities = activitiesByDate.get(date) ?? [];
                row.data = {
                    summary: summaryByDate.get(date) ?? null,
                    activities: dayActivities,
                    burn: dayBurnKcal(dayActivities, weightKgOnDate(weights, date)),
                    hasCoaching: coachingSet === null ? null : coachingSet.has(date),
                };
            }
            errorEl.hidden = true;
            retryEl.hidden = true;
        } catch (err) {
            this.log.error('Failed to load timeline window', from.toString(), to.toString(), err);
            errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
            errorEl.hidden = false;
            retryEl.hidden = false;
        }
    }
}

if (!customElements.get('health-timeline')) {
    customElements.define('health-timeline', HealthTimeline);
}
