import stylesText from './week-widget.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { formatMacro } from '../../../utils/format-macro.js';
import { HealthService } from '../../../services/health.service.js';
import { getHealthTargets, healthTargetsService } from '../../../services/health-targets.service.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { navigate } from '../../../router.js';
import { appTodayPlainDate } from '../../../services/app-timezone.service.js';
import { activityIcon, formatSteps } from '../health-utils.js';
import { dayBurnKcal, weightKgOnDate } from '@motivation/shared';
import type { Activity, DailyNutritionSummary, DailySteps, HealthStats, WeightEntry } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

/**
 * Story 258 — the combined week widget (wireframe 3a): streak / average-steps
 * / week-balance pills, a 7-day net-calorie graph (solid net bar + dashed
 * burned-off cap, dashed budget line), a workout-icon row (walks omitted), a
 * two-half dot row (activity done | step goal met), and the coaching teaser.
 * Replaces `coaching-card` and `calorie-trend-chart`.
 *
 * The coaching teaser is server-only data (not synced) — it hides on failure
 * instead of erroring, so the widget stays useful offline.
 */
const GRAPH_DAYS = 7;
/** Weight lookback so MET burn estimates have a plausible body weight. */
const WEIGHT_LOOKBACK_DAYS = 90;

interface WeekData {
    stats: HealthStats;
    summaries: DailyNutritionSummary[];
    activities: Activity[];
    steps: DailySteps[];
    weights: WeightEntry[];
}

const template = document.createElement('template');
template.innerHTML = `
    <p class="screen-loading" hidden>Loading…</p>
    <pre class="screen-error" hidden></pre>
    <button class="screen-retry" type="button" hidden>Retry</button>
    <div class="ww" id="ww" hidden>
        <div class="ww-pills">
            <span class="ww-pill" id="pill-streak" hidden></span>
            <span class="ww-pill" id="pill-steps" hidden></span>
            <span class="ww-spacer"></span>
            <span class="ww-pill ww-pill-wk" id="pill-wk" hidden></span>
            <button class="ww-edit" id="edit-targets" type="button" title="Edit targets">✎</button>
        </div>
        <div class="ww-graph">
            <div class="ww-budget-line" id="budget-line"><span class="ww-budget-label" id="budget-label"></span></div>
            <div class="ww-cols" id="cols"></div>
        </div>
        <div class="ww-icons" id="icons"></div>
        <div class="ww-dots" id="dots"></div>
        <button class="ww-teaser" id="teaser" type="button" hidden>
            <span class="ww-teaser-text" id="teaser-text"></span><span class="ww-teaser-arrow">›</span>
        </button>
    </div>
    <dialog class="targets-dialog" id="targets-dialog">
        <form method="dialog" id="targets-form">
            <h2>Targets</h2>
            <div class="form-group">
                <label for="target-budget">Calorie budget (kcal/day)</label>
                <input type="number" id="target-budget" name="budget" min="1" required>
            </div>
            <div class="form-group">
                <label for="target-protein">Protein target (g/day)</label>
                <input type="number" id="target-protein" name="protein" min="1" required>
            </div>
            <div class="form-group">
                <label for="target-steps">Step goal (steps/day)</label>
                <input type="number" id="target-steps" name="steps" min="1" required>
            </div>
            <div class="dialog-actions">
                <button value="cancel" formnovalidate>Cancel</button>
                <button value="save" class="btn-primary">Save</button>
            </div>
        </form>
    </dialog>
`;

export class WeekWidget extends HTMLElement {
    private readonly log = createComponentLogger('week-widget');
    private loadSequence = 0;
    private data: WeekData | null = null;
    private unsubscribeTargets: (() => void) | null = null;
    /** Resolves when the most recent load() finishes — for tests and awaits. */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        shadow.querySelector<HTMLButtonElement>('.screen-retry')!.addEventListener('click', () => { this.load(); });
        shadow.getElementById('teaser')!.addEventListener('click', () => navigate('/health/coaching'));
        shadow.getElementById('edit-targets')!.addEventListener('click', () => this.openTargetsDialog());
        this.wireTargetsDialog();
    }

    connectedCallback(): void {
        // Targets resolve asynchronously at boot (and can be edited from other
        // screens) — re-render this widget's cached data when they change.
        this.unsubscribeTargets = healthTargetsService.onChange(() => this.render());
        this.load();
    }

    disconnectedCallback(): void {
        this.unsubscribeTargets?.();
        this.unsubscribeTargets = null;
    }

    load(): Promise<void> {
        const currentLoad = ++this.loadSequence;
        this.setLoading();
        this.loadPromise = (async () => {
            try {
                const today = appTodayPlainDate();
                // The wk pill needs the 7 *completed* days (today − 7 … today − 1),
                // the graph needs today − 6 … today: fetch the 8-day union once.
                const from = today.subtract({ days: GRAPH_DAYS }).toString();
                const to = today.toString();
                const weightFrom = today.subtract({ days: GRAPH_DAYS + WEIGHT_LOOKBACK_DAYS }).toString();
                const [stats, summaries, activities, steps, weights] = await Promise.all([
                    HealthService.fetchStats(),
                    HealthService.fetchNutritionSummary(from, to),
                    HealthService.fetchMeaningfulActivitiesByDateRange(from, to),
                    HealthService.fetchDailySteps(from, to),
                    HealthService.fetchWeightByDateRange(weightFrom, to),
                ]);
                if (currentLoad !== this.loadSequence) return;
                this.data = { stats, summaries, activities, steps, weights };
                this.render();
                await this.loadTeaser(currentLoad);
            } catch (err) {
                if (currentLoad !== this.loadSequence) return;
                this.log.error('Failed to load week widget', err);
                this.setError(err);
            }
        })();
        return this.loadPromise;
    }

    /** Coaching is server-only — offline the teaser hides, the widget stays. */
    private async loadTeaser(currentLoad: number): Promise<void> {
        const teaser = this.shadowRoot!.getElementById('teaser')!;
        try {
            const coaching = await HealthService.fetchCoaching();
            if (currentLoad !== this.loadSequence) return;
            // Story 261: prefer the purpose-written headline; fall back to the
            // briefing's first line for pre-261 entries or a null/blank headline.
            const line = coaching?.headline?.trim() || firstAdviceLine(coaching?.advice ?? null);
            if (!line) {
                teaser.hidden = true;
                return;
            }
            this.shadowRoot!.getElementById('teaser-text')!.textContent = `💬 ${line}`;
            teaser.hidden = false;
        } catch (err) {
            if (currentLoad !== this.loadSequence) return;
            this.log.error('Coaching teaser unavailable (hiding)', err);
            teaser.hidden = true;
        }
    }

    private render(): void {
        if (!this.data) return;
        const { stats, summaries, activities, steps, weights } = this.data;
        const targets = getHealthTargets();
        const shadow = this.shadowRoot!;
        const today = appTodayPlainDate();

        const summaryByDate = new Map(summaries.map((s) => [s.date, s]));
        const activitiesByDate = new Map<string, Activity[]>();
        for (const activity of activities) {
            const list = activitiesByDate.get(activity.date) ?? [];
            list.push(activity);
            activitiesByDate.set(activity.date, list);
        }
        const stepsByDate = new Map(steps.map((s) => [s.date, s.steps]));

        const eatenOn = (date: string): number => summaryByDate.get(date)?.total_calories ?? 0;
        const burnOn = (date: string): number =>
            dayBurnKcal(activitiesByDate.get(date) ?? [], weightKgOnDate(weights, date)).kcal;

        // Pills.
        const streakPill = shadow.getElementById('pill-streak')!;
        streakPill.textContent = `🔥 ${stats.streak_days}`;
        streakPill.hidden = false;

        const graphDates: string[] = [];
        for (let i = GRAPH_DAYS - 1; i >= 0; i--) {
            graphDates.push(today.subtract({ days: i }).toString());
        }
        const stepCounts = graphDates.map((d) => stepsByDate.get(d)).filter((s): s is number => s != null && s > 0);
        const stepsPill = shadow.getElementById('pill-steps')!;
        if (stepCounts.length > 0) {
            const avg = stepCounts.reduce((sum, s) => sum + s, 0) / stepCounts.length;
            stepsPill.textContent = `👣 ⌀ ${formatSteps(avg)}`;
            stepsPill.hidden = false;
        } else {
            stepsPill.hidden = true;
        }

        // wk pill: Σ(net − budget) over the 7 *completed* days that have logged
        // food — today is excluded because a partial day flatters the number.
        let wkDiff = 0;
        let wkCounted = 0;
        for (let i = 1; i <= GRAPH_DAYS; i++) {
            const date = today.subtract({ days: i }).toString();
            const daySummary = summaryByDate.get(date);
            if (!daySummary || daySummary.entry_count === 0) continue;
            wkDiff += (daySummary.total_calories - burnOn(date)) - targets.calorie_budget_kcal;
            wkCounted++;
        }
        const wkPill = shadow.getElementById('pill-wk')!;
        if (wkCounted > 0) {
            const rounded = Math.round(wkDiff);
            wkPill.textContent = `wk ${rounded >= 0 ? '+' : '−'}${formatMacro(Math.abs(rounded))}`;
            wkPill.classList.toggle('is-over', rounded > 0);
            wkPill.hidden = false;
        } else {
            wkPill.hidden = true;
        }

        // Graph columns: solid bar = net, dashed cap above = the burned-off
        // part (cap top = eaten). Ceiling fits the tallest eaten total.
        const ceiling = Math.max(...graphDates.map((d) => eatenOn(d)), targets.calorie_budget_kcal * 1.2, 1);
        const cols = shadow.getElementById('cols')!;
        cols.replaceChildren();
        const icons = shadow.getElementById('icons')!;
        icons.replaceChildren();
        const dots = shadow.getElementById('dots')!;
        dots.replaceChildren();

        for (const date of graphDates) {
            const isToday = date === today.toString();
            const eaten = eatenOn(date);
            const burn = burnOn(date);
            const net = Math.max(eaten - burn, 0);

            const col = document.createElement('button');
            col.type = 'button';
            col.className = 'ww-col';
            col.dataset.date = date;
            col.classList.toggle('is-today', isToday);
            col.title = `${date} · ${formatMacro(eaten)} kcal`;
            const burnCap = document.createElement('div');
            burnCap.className = 'col-burn';
            burnCap.style.height = `${(Math.min(burn, eaten) / ceiling) * 100}%`;
            burnCap.hidden = burn <= 0 || eaten <= 0;
            const netBar = document.createElement('div');
            netBar.className = 'col-net';
            netBar.style.height = `${(net / ceiling) * 100}%`;
            col.appendChild(burnCap);
            col.appendChild(netBar);
            col.addEventListener('click', () => navigate(`/health/day/${date}`));
            cols.appendChild(col);

            // Walks stay out of the icon row — the dot's activity half carries
            // that signal without crowding out the real workouts.
            const dayActivities = activitiesByDate.get(date) ?? [];
            const icon = document.createElement('span');
            icon.className = 'ww-icon';
            icon.dataset.date = date;
            const types = [...new Set(dayActivities.filter((a) => a.type !== 'walking').map((a) => a.type))];
            if (types.length > 0) {
                icon.textContent = types.slice(0, 2).map(activityIcon).join('');
            } else {
                icon.textContent = isToday ? '?' : '—';
                icon.classList.toggle('is-open', isToday);
            }
            icons.appendChild(icon);

            // Two-half dot: left half = any activity logged, right = step goal.
            const dot = document.createElement('span');
            dot.className = 'ww-dot';
            dot.dataset.date = date;
            const daySteps = stepsByDate.get(date);
            dot.classList.toggle('act-met', dayActivities.length > 0);
            dot.classList.toggle('steps-met', daySteps != null && daySteps >= targets.step_goal);
            dot.classList.toggle('is-today', isToday);
            const circle = document.createElement('span');
            circle.className = 'dot-circle';
            dot.appendChild(circle);
            dots.appendChild(dot);
        }

        const budgetLine = shadow.getElementById('budget-line')!;
        budgetLine.style.bottom = `${(targets.calorie_budget_kcal / ceiling) * 100}%`;
        shadow.getElementById('budget-label')!.textContent = formatMacro(targets.calorie_budget_kcal);

        shadow.getElementById('ww')!.hidden = false;
        shadow.querySelector<HTMLElement>('.screen-loading')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-error')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-retry')!.hidden = true;
    }

    private openTargetsDialog(): void {
        const shadow = this.shadowRoot!;
        const targets = getHealthTargets();
        shadow.querySelector<HTMLInputElement>('#target-budget')!.value = String(targets.calorie_budget_kcal);
        shadow.querySelector<HTMLInputElement>('#target-protein')!.value = String(targets.protein_target_g);
        shadow.querySelector<HTMLInputElement>('#target-steps')!.value = String(targets.step_goal);
        shadow.querySelector<HTMLDialogElement>('#targets-dialog')!.showModal();
    }

    private wireTargetsDialog(): void {
        const shadow = this.shadowRoot!;
        const dialog = shadow.querySelector<HTMLDialogElement>('#targets-dialog')!;
        dialog.addEventListener('close', async () => {
            if (dialog.returnValue !== 'save') return;
            try {
                // setTargets notifies onChange, which re-renders this widget.
                await healthTargetsService.setTargets({
                    calorie_budget_kcal: Number(shadow.querySelector<HTMLInputElement>('#target-budget')!.value),
                    protein_target_g: Number(shadow.querySelector<HTMLInputElement>('#target-protein')!.value),
                    step_goal: Number(shadow.querySelector<HTMLInputElement>('#target-steps')!.value),
                });
            } catch (err) {
                this.log.error('Failed to save health targets', err);
                this.setError(err);
            }
        });
    }

    private setLoading(): void {
        const shadow = this.shadowRoot!;
        shadow.querySelector<HTMLElement>('.screen-loading')!.hidden = false;
        shadow.querySelector<HTMLElement>('.screen-error')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-retry')!.hidden = true;
        shadow.getElementById('ww')!.hidden = true;
    }

    private setError(err: unknown): void {
        const shadow = this.shadowRoot!;
        const errorEl = shadow.querySelector<HTMLElement>('.screen-error')!;
        errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        errorEl.hidden = false;
        shadow.querySelector<HTMLElement>('.screen-loading')!.hidden = true;
        shadow.querySelector<HTMLElement>('.screen-retry')!.hidden = false;
        shadow.getElementById('ww')!.hidden = true;
    }
}

/** First non-empty advice line, stripped of markdown heading/list prefixes. */
function firstAdviceLine(advice: string | null): string | null {
    if (!advice) return null;
    for (const raw of advice.split('\n')) {
        const line = raw.replace(/^[#*\-\s>]+/, '').trim();
        if (line.length > 0) return line;
    }
    return null;
}

if (!customElements.get('week-widget')) {
    customElements.define('week-widget', WeekWidget);
}
