import stylesText from './timeline-day.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { formatMacro } from '../../../../utils/format-macro.js';
import { navigate } from '../../../../router.js';
import { appTodayPlainDate } from '../../../../services/app-timezone.service.js';
import { getHealthTargets, healthTargetsService } from '../../../../services/health-targets.service.js';
import { activityIcon, formatDurationMinutes } from '../../health-utils.js';
import type { Activity, ActivityBurn, DailyNutritionSummary } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

/**
 * Story 258 v3 — one spine day row (wireframe 3a). Deliberately does no
 * fetching: `health-timeline` loads each page window in ranged reads and
 * hands every row its slice via the `data` property. Burned kcal sit on the
 * LEFT with the workouts, consumed kcal on the RIGHT — the row computes no
 * net (owner call: the reader does the mental math).
 */
export interface TimelineDayData {
    summary: DailyNutritionSummary | null;
    activities: Activity[];
    /** Day burn (real-or-estimated); null when unknown. */
    burn: ActivityBurn | null;
    /** null = unknown (coaching is server-only and we are offline) → dot hides. */
    hasCoaching: boolean | null;
}

/** The overflow cap never grows past this share of the bar (wireframe scale). */
const MAX_OVERFLOW_FRACTION = 0.25;

/**
 * The workout pills must stay on ONE row. When a level overflows the pane the
 * row degrades to the next: 0 = one pill per workout (walks folded, story
 * 254) → 1 = one pill per type with aggregate time → 2 = icons only.
 */
const MAX_PILL_LEVEL = 2;

/** Per-type totals: non-walking types in first-seen order, walking last (the level-0 ordering). */
function groupByType(activities: Activity[]): { type: string; total: number }[] {
    const totals = new Map<string, number>();
    for (const activity of activities) {
        if (activity.type === 'walking') continue;
        totals.set(activity.type, (totals.get(activity.type) ?? 0) + (activity.duration_minutes ?? 0));
    }
    const groups = [...totals].map(([type, total]) => ({ type, total }));
    const walks = activities.filter((a) => a.type === 'walking');
    if (walks.length > 0) {
        groups.push({ type: 'walking', total: walks.reduce((sum, walk) => sum + (walk.duration_minutes ?? 0), 0) });
    }
    return groups;
}

function pillTexts(activities: Activity[], level: number): string[] {
    if (level <= 0) {
        const walks = activities.filter((a) => a.type === 'walking');
        const rest = activities.filter((a) => a.type !== 'walking');
        const texts = rest.map((w) => `${activityIcon(w.type)} ${formatDurationMinutes(w.duration_minutes)}`.trim());
        if (walks.length === 1) {
            texts.push(`${activityIcon('walking')} ${formatDurationMinutes(walks[0].duration_minutes)}`.trim());
        } else if (walks.length > 1) {
            const total = walks.reduce((sum, walk) => sum + (walk.duration_minutes ?? 0), 0);
            texts.push(`${activityIcon('walking')} ${walks.length}× ${formatDurationMinutes(total)}`.trim());
        }
        return texts;
    }
    if (level === 1) {
        return groupByType(activities).map((g) => `${activityIcon(g.type)} ${formatDurationMinutes(g.total)}`.trim());
    }
    return groupByType(activities).map((g) => activityIcon(g.type));
}

const template = document.createElement('template');
template.innerHTML = `
    <div class="timeline-day" id="day-row">
        <div class="left-pane">
            <div class="date-label" id="date-label"></div>
            <div class="day-pills" id="day-pills"></div>
            <div class="day-burn" id="day-burn" hidden></div>
        </div>
        <button class="spine-node" id="coach-dot" type="button" title="Coaching">💬</button>
        <div class="right-pane">
            <div class="day-card">
                <div class="day-nums">
                    <span class="day-kcal" id="day-kcal">—</span>
                    <span class="day-protein" id="day-protein"></span>
                </div>
                <div class="kcal-track">
                    <div class="kcal-fill" id="kcal-fill"></div>
                    <div class="kcal-overflow" id="kcal-overflow" hidden></div>
                </div>
                <div class="protein-track">
                    <div class="protein-fill" id="protein-fill"></div>
                </div>
            </div>
        </div>
    </div>
`;

export class TimelineDay extends HTMLElement {
    static readonly observedAttributes = ['date'];
    private _data: TimelineDayData | null = null;
    private unsubscribeTargets: (() => void) | null = null;
    private resizeObserver: ResizeObserver | null = null;

    connectedCallback(): void {
        // The bars scale against the targets, which resolve asynchronously at
        // boot (and can be edited from the week widget) — re-render then.
        this.unsubscribeTargets = healthTargetsService.onChange(() => this.render());
        // Pill fitting needs real geometry: rows rendered while offscreen
        // (content-visibility) or before layout measure 0/0 and stay at level
        // 0 — refit when the pane gets its actual size (also covers viewport
        // resizes). Absent in happy-dom, hence the guard.
        if (typeof ResizeObserver !== 'undefined') {
            this.resizeObserver = new ResizeObserver(() => this.render());
            this.resizeObserver.observe(this.shadowRoot!.querySelector('.left-pane')!);
        }
    }

    disconnectedCallback(): void {
        this.unsubscribeTargets?.();
        this.unsubscribeTargets = null;
        this.resizeObserver?.disconnect();
        this.resizeObserver = null;
    }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        shadow.getElementById('day-row')!.addEventListener('click', () => {
            const date = this.getAttribute('date');
            if (date) navigate(`/health/day/${date}`);
        });
        shadow.getElementById('coach-dot')!.addEventListener('click', (event) => {
            event.stopPropagation();
            const date = this.getAttribute('date');
            if (date) navigate(`/health/coaching/${date}`);
        });
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name !== 'date' || !newValue) return;
        this.shadowRoot!.getElementById('date-label')!.textContent = this.formatDateLabel(newValue);
        this.shadowRoot!.getElementById('day-row')!.classList.toggle(
            'is-today',
            newValue === appTodayPlainDate().toString(),
        );
    }

    set data(value: TimelineDayData) {
        this._data = value;
        this.render();
    }

    get data(): TimelineDayData | null {
        return this._data;
    }

    private render(): void {
        if (!this._data) return;
        const { summary, activities, burn, hasCoaching } = this._data;
        const targets = getHealthTargets();
        const shadow = this.shadowRoot!;

        // Left: workout pills on a single row — real workouts first, walks
        // fold into one grouped pill (story 254 behavior carried over); the
        // row degrades level by level until it fits. Then the day burn.
        const pills = shadow.getElementById('day-pills')!;
        if (activities.length === 0) {
            const dash = document.createElement('span');
            dash.className = 'day-empty';
            dash.textContent = '—';
            pills.replaceChildren(dash);
        } else {
            for (let level = 0; ; level++) {
                // The row is `row-reverse` (so overflow is measurable — see
                // pillRowOverflows); reverse the pills so they still read
                // workouts-first, walks-last left-to-right on screen.
                pills.replaceChildren(...pillTexts(activities, level).reverse().map(buildPill));
                if (level >= MAX_PILL_LEVEL || !this.pillRowOverflows(pills)) break;
            }
        }

        const burnEl = shadow.getElementById('day-burn')!;
        if (burn && burn.kcal > 0) {
            burnEl.textContent = `🔥 ${burn.estimated ? '~' : ''}${formatMacro(burn.kcal)}`;
            burnEl.hidden = false;
        } else {
            burnEl.hidden = true;
        }

        // Spine dot — coaching presence. Unknown (offline) hides the dot.
        const dot = shadow.getElementById('coach-dot')!;
        dot.hidden = hasCoaching === null;
        dot.classList.toggle('has-coaching', hasCoaching === true);

        // Right: consumed kcal + protein against the targets.
        const eaten = summary?.total_calories ?? 0;
        const protein = summary?.total_protein_g ?? 0;
        shadow.getElementById('day-kcal')!.textContent = summary ? formatMacro(eaten) : '—';
        shadow.getElementById('day-protein')!.textContent = summary ? `P ${formatMacro(protein)}` : '';

        const budget = targets.calorie_budget_kcal;
        shadow.getElementById('kcal-fill')!.style.width = `${Math.min(eaten / budget, 1) * 100}%`;
        const overflow = shadow.getElementById('kcal-overflow')!;
        if (eaten > budget) {
            overflow.style.width = `${Math.min((eaten - budget) / budget, MAX_OVERFLOW_FRACTION) * 100}%`;
            overflow.hidden = false;
        } else {
            overflow.hidden = true;
        }
        shadow.getElementById('protein-fill')!.style.width =
            `${Math.min(protein / targets.protein_target_g, 1) * 100}%`;
    }

    /**
     * Whether the pill row spills past the pane. A real method (not inlined)
     * so unit tests can stub it — happy-dom has no layout and reports 0/0,
     * which correctly reads as "fits" until the ResizeObserver refit.
     *
     * The row is `flex-direction: row-reverse` (see `.day-pills`) precisely so
     * overflow spills off the scrollable end edge, where `scrollWidth` can
     * measure it — `justify-content: flex-end` spilled off the unreachable
     * start edge and `scrollWidth` never grew past `clientWidth`.
     */
    pillRowOverflows(container: HTMLElement): boolean {
        return container.scrollWidth > container.clientWidth + 1;
    }

    private formatDateLabel(dateStr: string): string {
        const date = Temporal.PlainDate.from(dateStr);
        const today = appTodayPlainDate();
        if (date.equals(today)) return 'Today';
        if (date.equals(today.subtract({ days: 1 }))) return 'Yesterday';
        return date.toLocaleString(undefined, { day: 'numeric', month: 'short' });
    }
}

function buildPill(text: string): HTMLElement {
    const pill = document.createElement('span');
    pill.className = 'day-pill';
    pill.textContent = text;
    return pill;
}

if (!customElements.get('timeline-day')) {
    customElements.define('timeline-day', TimelineDay);
}
